SET NOCOUNT ON;
DROP TABLE IF EXISTS #schoolgradelevel;

CREATE TABLE #schoolgradelevel ([SchoolId] int, [GradeLevelCodeValue] nvarchar(50), [GradeLevelNamespace] nvarchar(255) )

;WITH schoolgradelevel AS 
(
	SELECT 
		s.SchoolId,
		gld.GradeLevelDescriptorId
	FROM #schoolgradelevel s
	JOIN edfi.Descriptor d
		ON s.GradeLevelCodeValue = d.CodeValue
		AND s.GradeLevelNamespace = d.Namespace
	JOIN edfi.GradeLevelDescriptor gld
		ON d.DescriptorId = gld.GradeLevelDescriptorId
	JOIN edfi.EducationOrganization eo
		ON s.SchoolId = eo.EducationOrganizationId
	JOIN edfi.School sc
		ON s.SchoolId = sc.SchoolId 
) 
MERGE INTO edfi.SchoolGradeLevel AS tgt
USING schoolgradelevel AS src 
	ON tgt.SchoolId = src.SchoolId
	AND tgt.GradeLevelDescriptorId = src.GradeLevelDescriptorId
WHEN NOT MATCHED THEN 
	INSERT (SchoolId, GradeLevelDescriptorId)
	VALUES (src.SchoolId, src.GradeLevelDescriptorId)
;


DROP TABLE #schoolgradelevel
SET NOCOUNT OFF;
